import { Program } from '../core/program';
import { Declaration, ForeignImport, CallExpression, FunctionDeclaration } from '../core/ast';

export function emitHaskell(program: Program): string {
  let out = '';
  let needsCString = false;

  for (const mod of program.modules) {
    const foreignNames = new Set(mod.declarations.filter(d => d.kind === 'ForeignImport').map(d => d.name.name));
    out += `-- Module: ${mod.name}

`;

    for (const item of mod.declarations) {
      if (item.kind === 'ForeignImport') {
        const f = item as ForeignImport;
        if (f.signature.params.includes('string') || f.signature.result === 'string') needsCString = true;
        const params = f.signature.params.map(t => mapHaskellType(t)).join(' -> ');
        const ret = mapHaskellType(f.signature.result);
        out += `foreign import ccall "${f.symbol}" ${f.name.name} :: ${params} -> IO ${ret}

`;
      }
    }

    for (const item of mod.declarations) {
      if (item.kind === 'FunctionDeclaration') {
        const fn = item as FunctionDeclaration;
        const params = fn.signature.params.map(t => mapHaskellType(t));
        const sig = [...params, mapHaskellType(fn.signature.result)].join(' -> ');
        out += `${fn.name.name} :: ${sig}
`;
        out += `${fn.name.name} ${fn.params.map(p => p.name).join(' ')} = ${emitHaskellExpr(fn.body)}

`;
      }
      if (item.kind === 'Declaration') {
        const d = item as Declaration;
        if (d.value.kind === 'CallExpression' && foreignNames.has((d.value as CallExpression).callee.name)) {
          const call = d.value as CallExpression;
          const foreign = mod.declarations.find(f => f.kind === 'ForeignImport' && f.name.name === call.callee.name) as ForeignImport | undefined;
          const retType = foreign ? mapHaskellType(foreign.signature.result) : 'Int';
          out += `${d.name.name} :: IO ${retType}
`;
          const body = foreign ? emitHaskellForeignCall(call, foreign) : emitPlainHaskellCall(call);
          out += `${d.name.name} = ${body}

`;
        } else {
          out += `${d.name.name} = ${emitHaskellExpr(d.value)}

`;
        }
      }
    }
  }

  if (needsCString) {
    out = `import Foreign.C.String (CString, withCString)

${out}`;
  }
  return out.trim();
}

function mapHaskellType(t: string): string {
  if (t === 'i32') return 'Int';
  if (t === 'f64') return 'Double';
  if (t === 'bool') return 'Bool';
  if (t === 'string') return 'CString';
  return '()';
}

function mapHaskellBinaryOperator(op: string): string {
  if (op === '!=') return '/=';
  return op;
}

function parenIfNeeded(s: string): string {
  return s.startsWith('(') && s.endsWith(')') ? s : `(${s})`;
}

function expressionKind(e: any): string {
  if (e && typeof e.kind === 'string') return e.kind;
  return typeof e;
}

function emitPlainHaskellCall(call: CallExpression): string {
  const args = call.arguments.map(a => emitHaskellExpr(a)).join(' ');
  return args.length > 0 ? `${call.callee.name} ${args}` : call.callee.name;
}

function emitForeignArgSource(arg: any): string {
  const emitted = emitHaskellExpr(arg);
  if (arg.kind === 'Literal' || arg.kind === 'Identifier') return emitted;
  return parenIfNeeded(emitted);
}

function emitHaskellForeignCall(call: CallExpression, foreign: ForeignImport): string {
  const stringBindings: { name: string; source: string }[] = [];
  const args = call.arguments.map((arg, i) => {
    if (foreign.signature.params[i] === 'string') {
      const name = `arg${i}`;
      stringBindings.push({ name, source: emitForeignArgSource(arg) });
      return name;
    }
    return emitHaskellExpr(arg);
  });
  const base = args.length > 0 ? `${call.callee.name} ${args.join(' ')}` : call.callee.name;
  return stringBindings.reduceRight((body, binding) => `withCString ${binding.source} $ \\${binding.name} -> ${body}`, base);
}

function emitHaskellExpr(e: any): string {
  if (e.kind === 'Literal') {
    if (typeof e.value === 'boolean') return e.value ? 'True' : 'False';
    if (typeof e.value === 'string') return JSON.stringify(e.value);
    return String(e.value);
  }
  if (e.kind === 'Identifier') return e.name;
  if (e.kind === 'CallExpression') {
    const args = e.arguments.map((arg: any) => {
      const emitted = emitHaskellExpr(arg);
      if (arg.kind === 'Literal' || arg.kind === 'Identifier') return emitted;
      return parenIfNeeded(emitted);
    }).join(' ');
    return args.length > 0 ? `${e.callee.name} ${args}` : e.callee.name;
  }
  if (e.kind === 'BinaryExpression') return `(${emitHaskellExpr(e.left)} ${mapHaskellBinaryOperator(e.operator)} ${emitHaskellExpr(e.right)})`;
  if (e.kind === 'IfExpression') return `(if ${emitHaskellExpr(e.condition)} then ${emitHaskellExpr(e.thenBranch)} else ${emitHaskellExpr(e.elseBranch)})`;
  if (e.kind === 'LetExpression') return `(let ${e.name.name} = ${emitHaskellExpr(e.value)} in ${emitHaskellExpr(e.body)})`;
  throw new Error(`Haskell backend unsupported expression kind: ${expressionKind(e)}`);
}

import { parse } from '../src/parser';
import { checkProgram } from '../src/core/check';
import { emitTypeScript } from '../src/codegen/typescript';
import { emitHaskell } from '../src/codegen/haskell';
import { runLsc } from '../src/cli/lsc';
import * as fs from 'fs';
import path from 'path';
import assert from 'node:assert/strict';

interface FixtureExpectation {
  file: string;
  tsIncludes: string[];
  hsIncludes: string[];
  tsExcludes?: string[];
  hsExcludes?: string[];
}

function checkFixture(fixture: FixtureExpectation) {
  const fixturePath = path.resolve(__dirname, '../../..', fixture.file);
  const src = fs.readFileSync(fixturePath, 'utf8');
  const pr = parse(src, fixturePath);
  assert.strictEqual(pr.diagnostics.length, 0, `${fixture.file} parse diagnostics`);
  const c = checkProgram(pr.program!);
  assert.strictEqual(c.diagnostics.length, 0, `${fixture.file} check diagnostics`);
  const ts = emitTypeScript(pr.program!);
  const hs = emitHaskell(pr.program!);
  for (const expected of fixture.tsIncludes) {
    assert.ok(ts.includes(expected), `${fixture.file} TypeScript output should include ${expected}`);
  }
  for (const expected of fixture.hsIncludes) {
    assert.ok(hs.includes(expected), `${fixture.file} Haskell output should include ${expected}`);
  }
  for (const rejected of fixture.tsExcludes ?? []) {
    assert.ok(!ts.includes(rejected), `${fixture.file} TypeScript output should not include ${rejected}`);
  }
  for (const rejected of fixture.hsExcludes ?? []) {
    assert.ok(!hs.includes(rejected), `${fixture.file} Haskell output should not include ${rejected}`);
  }
  const originalError = console.error;
  try {
    console.error = () => {};
    assert.strictEqual(runLsc(['emit', fixturePath, '--target', 'py']), 1, `${fixture.file} should reject py target`);
    assert.strictEqual(runLsc(['emit', fixturePath, '--target', 'python']), 1, `${fixture.file} should reject python target`);
  } finally {
    console.error = originalError;
  }
}

function checkFails(name: string, source: string, expected: string) {
  const pr = parse(source, `${name}.ls`);
  assert.strictEqual(pr.diagnostics.length, 0, `${name} should parse`);
  const c = checkProgram(pr.program!);
  assert.ok(c.diagnostics.some(d => d.message.includes(expected)), `${name} should report ${expected}, got ${c.diagnostics.map(d => d.message).join('; ')}`);
}

function parseFails(name: string, source: string, expected: string) {
  const pr = parse(source, `${name}.ls`);
  assert.ok(pr.diagnostics.some(d => d.message.includes(expected)), `${name} should report ${expected}, got ${pr.diagnostics.map(d => d.message).join('; ')}`);
}

function checkUnsupportedBackendErrors() {
  const badProgram: any = {
    kind: 'Program',
    modules: [
      {
        kind: 'Module',
        name: 'BadBackend',
        declarations: [
          {
            kind: 'Declaration',
            name: { kind: 'Identifier', name: 'bad' },
            value: { kind: 'MysteryExpression' },
          },
        ],
      },
    ],
  };

  assert.throws(
    () => emitTypeScript(badProgram),
    /TypeScript backend unsupported expression kind: MysteryExpression/,
    'TypeScript backend should reject unsupported expression kinds clearly',
  );
  assert.throws(
    () => emitHaskell(badProgram),
    /Haskell backend unsupported expression kind: MysteryExpression/,
    'Haskell backend should reject unsupported expression kinds clearly',
  );
}

function checkHaskellNotEqualEmission() {
  const source = `module Compare

is_not : i32 -> i32 -> bool
is_not x y = x != y
`;
  const pr = parse(source, 'not-equal.ls');
  assert.strictEqual(pr.diagnostics.length, 0, 'not-equal should parse');
  const c = checkProgram(pr.program!);
  assert.strictEqual(c.diagnostics.length, 0, `not-equal should check, got ${c.diagnostics.map(d => d.message).join('; ')}`);

  const ts = emitTypeScript(pr.program!);
  const hs = emitHaskell(pr.program!);
  assert.ok(ts.includes('return (x != y);'), 'TypeScript should preserve LambdaScript != as target-valid !=');
  assert.ok(hs.includes('is_not x y = (x /= y)'), 'Haskell should emit LambdaScript != as /=');
  assert.ok(!hs.includes('!='), 'Haskell output should not contain raw !=');
}

function checkHaskellForeignStringNesting() {
  const source = `module ForeignStrings

foreign cpp join_message : string -> string -> void = "ls_join_message"
first = "alpha"
done = join_message(first, "beta")
`;
  const pr = parse(source, 'foreign-strings.ls');
  assert.strictEqual(pr.diagnostics.length, 0, 'foreign string nesting should parse');
  const c = checkProgram(pr.program!);
  assert.strictEqual(c.diagnostics.length, 0, `foreign string nesting should check, got ${c.diagnostics.map(d => d.message).join('; ')}`);

  const ts = emitTypeScript(pr.program!);
  const hs = emitHaskell(pr.program!);
  assert.ok(ts.includes('join_message(runtime, first, "beta");'), 'TypeScript should pass string FFI arguments directly to runtime wrapper');
  assert.ok(hs.includes('done = withCString first $ \\arg0 -> withCString "beta" $ \\arg1 -> join_message arg0 arg1'), 'Haskell should convert each string FFI argument with nested withCString');
}

function main() {
  const fixtures: FixtureExpectation[] = [
    {
      file: 'examples/hello.ls',
      tsIncludes: ['export const answer = 42', 'export const name = "lambda"', 'export const flag = true'],
      hsIncludes: ['answer = 42', 'name = "lambda"', 'flag = True'],
    },
    {
      file: 'examples/core/core0_values.ls',
      tsIncludes: ['export const answer = 42', 'export const ratio = 3.5', 'export const flag = true'],
      hsIncludes: ['answer = 42', 'ratio = 3.5', 'flag = True'],
    },
    {
      file: 'examples/core/core0_ffi.ls',
      tsIncludes: [
        'export function add_i32',
        "symbol: 'ls_add_i32'",
        'export function answer(runtime: CppForeignRuntime): number',
        'export function log_message(runtime: CppForeignRuntime, arg0: string): void',
        'export function done(runtime: CppForeignRuntime): void',
        '  log_message(runtime, "hello from Core-0");',
      ],
      hsIncludes: ['foreign import ccall "ls_add_i32" add_i32', 'answer :: IO Int', 'scaled :: IO Double', 'done :: IO ()'],
      tsExcludes: ['return log_message(runtime, "hello from Core-0");', ': null'],
    },
    {
      file: 'examples/core/core1_functions.ls',
      tsIncludes: ['export function add(x: number, y: number): number', 'export function max_i32(x: number, y: number): number', 'return ((n <= 1) ? 1 : (n * fact((n - 1))))'],
      hsIncludes: ['add :: Int -> Int -> Int', 'max_i32 :: Int -> Int -> Int', 'fact n = (if (n <= 1) then 1 else (n * fact (n - 1)))'],
    },
    {
      file: 'examples/core/core1_let.ls',
      tsIncludes: ['export function square_plus(x: number, y: number): number', 'const xx = (x * x); return (xx + y)', 'const below = (x < floor); return (below ? floor : x)'],
      hsIncludes: ['square_plus :: Int -> Int -> Int', 'square_plus x y = (let xx = (x * x) in (xx + y))', 'clamp_min floor x = (let below = (x < floor) in (if below then floor else x))'],
    },
    {
      file: 'examples/core/core1_pure_calls.ls',
      tsIncludes: ['export const total = add(1, 2)', 'export const chosen = max_i32(add(1, 1), 3)'],
      hsIncludes: ['total = add 1 2', 'chosen = max_i32 (add 1 1) 3'],
    },
  ];
  for (const fixture of fixtures) checkFixture(fixture);
  checkUnsupportedBackendErrors();
  checkHaskellNotEqualEmission();
  checkHaskellForeignStringNesting();

  checkFails('unknown-variable', `module Bad

f : i32 -> i32
f x = y
`, 'Unknown identifier: y');
  checkFails('wrong-arity', `module Bad

add : i32 -> i32 -> i32
add x y = x + y
z = add(1)
`, 'Wrong argument count for add');
  checkFails('wrong-argument-type', `module Bad

add : i32 -> i32 -> i32
add x y = x + y
z = add(true, 1)
`, 'Argument 1 for add has type bool, expected i32');
  checkFails('if-condition-type', `module Bad

f : i32 -> i32
f x = if x then 1 else 2
`, 'If condition has type i32, expected bool');
  checkFails('if-branch-type', `module Bad

f : i32 -> i32
f x = if x < 1 then 1 else false
`, 'If branches have different types: i32 and bool');
  checkFails('return-type', `module Bad

f : i32 -> i32
f x = false
`, 'Function f returns bool, expected i32');
  checkFails('binary-type', `module Bad

f : bool -> bool
f x = x + true
`, 'Operator + expects numeric operands');
  parseFails('dangling-signature', `module Bad

f : i32 -> i32
`, 'Dangling type signature for f');
  parseFails('duplicate-signature', `module Bad

f : i32 -> i32
f : i32 -> i32
f x = x
`, 'Duplicate type signature for f');
  console.log('Smoke test passed');
}

main();
